def test_style_based_true_when_style_matches_and_outbound_count_boundary():
    # style in {"direct_number_request", "video_call_request", "whatsapp_coordination"} triggers True if outbound_count <= 1
    # We test with conversation_style that normalizes to one of these
    # Since normalize_conversation_style is external, we test by passing exact style strings that should match
    for style in ["direct_number_request", "video_call_request", "whatsapp_coordination"]:
        persona = {"mobile_number": "12345", "conversation_style": style}
        # phone_fetching_type fallback to "delayed" which does not trigger style logic, so we must set phone_fetching_type to a non-triggering value
        # But spec says style triggers True if style in those three regardless of phone_type? No, style triggers True only if phone_type in {"immediate", "whatsapp_first"} OR style in {...}
        # So style triggers True regardless of phone_type, so phone_type can be anything.
        # But phone_type fallback is "delayed" which triggers different logic, so style triggers True independently.
        # So test outbound_count 0 and 2 for boundary
        assert should_share_phone_now(persona, outbound_count=0) is True
        assert should_share_phone_now(persona, outbound_count=1) is True
        assert should_share_phone_now(persona, outbound_count=2) is False

def test_phone_fetching_type_fallback_to_delayed():
    persona = {"mobile_number": "12345", "phone_fetching_type": None}
    # delayed requires outbound_count >= 2 and stage == "VIEWING_BOOKED"
    assert should_share_phone_now(persona, outbound_count=2, stage="VIEWING_BOOKED") is True
    assert should_share_phone_now(persona, outbound_count=1, stage="VIEWING_BOOKED") is False

