import pytest
from types import SimpleNamespace
from app.ai.conversation_memory import phone_shared_state

def test_returns_true_if_conversation_phone_number_shared_at_truthy():
    conversation = SimpleNamespace(phone_number_shared_at=True)
    result = phone_shared_state([], None, conversation)
    assert result is True

def test_returns_false_if_no_conversation_and_no_mobile_number():
    # persona is None, messages empty
    result = phone_shared_state([], None, None)
    assert result is False

def test_returns_false_if_mobile_number_empty_and_no_messages():
    persona = {"mobile_number": ""}
    result = phone_shared_state([], persona, None)
    assert result is False

def test_returns_true_if_message_contains_local_number_with_uk_prefix():
    # mobile_number with +44 prefix, message contains local number starting with 0
    persona = {"mobile_number": "+44 7123 456789"}
    messages = [
        {"sender": "user", "message": "Call me on 07123456789"}
    ]
    result = phone_shared_state(messages, persona)
    assert result is True

def test_returns_true_if_message_contains_compact_number_and_sender_case_insensitive():
    # mobile_number without country code, message content contains exact digits, sender case insensitive
    persona = {"mobile_number": "07123456789"}
    messages = [
        {"sender": "Tenant", "content": "My number is 07123456789"}
    ]
    result = phone_shared_state(messages, persona)
    assert result is True

def test_ignores_messages_with_unknown_sender_and_fallback_keys_used():
    persona = {"mobile_number": "07123456789"}
    messages = [
        {"sender": "unknown", "message": "07123456789"},  # ignored sender
        {"direction": "system", "content": "07123456789"},  # ignored sender
        {"direction": "user", "message": None},  # empty content fallback
        {"sender": None, "direction": "outbound", "message": "Call 07123456789 now"},  # valid sender fallback
    ]
    result = phone_shared_state(messages, persona)
    assert result is True
